import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
class CardBrowserNotesModeSortTest : RobolectricTest() {

    /**
     * Test that when in NOTES mode, changing the sort order saves to noteSortType config key
     * instead of sortType config key.
     */
    @Test
    fun notesModeSavesToNoteSortTypeConfig() {
        val browser = browserWithMultipleNotes

        // Switch to NOTES mode
        browser.switchCardOrNote(CardsOrNotes.NOTES)

        // Change the sort order
        browser.changeCardOrder(SortType.EASE)

        // Verify that the sort type was saved to noteSortType, not sortType
        assertThat(
            "Notes mode should save sort type to noteSortType config",
            col.config.get<String>("noteSortType"),
            equalTo("cardEase")
        )
    }

    /**
     * Test that when in NOTES mode, the sort direction is saved to browserNoteSortBackwards
     * instead of sortBackwards.
     */
    @Test
    fun notesModeSavesSortDirectionToBrowserNoteSortBackwards() {
        val browser = browserWithMultipleNotes

        // Switch to NOTES mode
        browser.switchCardOrNote(CardsOrNotes.NOTES)

        // Change the sort order (first change sets ascending to false)
        browser.changeCardOrder(SortType.EASE)

        // Verify that sortBackwards was saved to browserNoteSortBackwards
        assertThat(
            "Notes mode should save sort direction to browserNoteSortBackwards config",
            col.config.get<Boolean>("browserNoteSortBackwards"),
            equalTo(false)
        )

        // Click the same sort type again to reverse the order
        browser.changeCardOrder(SortType.EASE)

        // Verify that the direction was reversed
        assertThat(
            "Reversing sort order should update browserNoteSortBackwards config",
            col.config.get<Boolean>("browserNoteSortBackwards"),
            equalTo(true)
        )
    }

    /**
     * Test that when in CARDS mode, changing the sort order still saves to sortType config key.
     */
    @Test
    fun cardsModeSavesToSortTypeConfig() {
        val browser = browserWithMultipleNotes

        // Ensure we're in CARDS mode (default)
        assertThat(browser.cardsOrNotes, equalTo(CardsOrNotes.CARDS))

        // Change the sort order
        browser.changeCardOrder(SortType.EASE)

        // Verify that the sort type was saved to sortType
        assertThat(
            "Cards mode should save sort type to sortType config",
            col.config.get<String>("sortType"),
            equalTo("cardEase")
        )
    }

    /**
     * Test that when in CARDS mode, the sort direction is saved to sortBackwards.
     */
    @Test
    fun cardsModeSavesSortDirectionToSortBackwards() {
        val browser = browserWithMultipleNotes

        // Ensure we're in CARDS mode (default)
        assertThat(browser.cardsOrNotes, equalTo(CardsOrNotes.CARDS))

        // Change the sort order
        browser.changeCardOrder(SortType.EASE)

        // Verify that sortBackwards was saved
        assertThat(
            "Cards mode should save sort direction to sortBackwards config",
            col.config.get<Boolean>("sortBackwards"),
            equalTo(false)
        )

        // Click the same sort type again to reverse the order
        browser.changeCardOrder(SortType.EASE)

        // Verify that the direction was reversed
        assertThat(
            "Reversing sort order should update sortBackwards config",
            col.config.get<Boolean>("sortBackwards"),
            equalTo(true)
        )
    }

    /**
     * Test that cards and notes modes maintain separate sort configurations.
     */
    @Test
    fun cardsAndNotesModesMaintainSeparateSortConfigs() {
        val browser = browserWithMultipleNotes

        // Set up CARDS mode with one sort type
        browser.changeCardOrder(SortType.EASE)
        col.config.set("sortBackwards", true)

        // Set up NOTES mode with a different sort type
        browser.switchCardOrNote(CardsOrNotes.NOTES)
        browser.changeCardOrder(SortType.CREATED_TIME)
        col.config.set("browserNoteSortBackwards", false)

        // Verify that the configurations are independent
        assertThat(
            "Cards mode sort type should be preserved",
            col.config.get<String>("sortType"),
            equalTo("cardEase")
        )
        assertThat(
            "Cards mode sort direction should be preserved",
            col.config.get<Boolean>("sortBackwards"),
            equalTo(true)
        )
        assertThat(
            "Notes mode sort type should be separate",
            col.config.get<String>("noteSortType"),
            equalTo("noteCrt")
        )
        assertThat(
            "Notes mode sort direction should be separate",
            col.config.get<Boolean>("browserNoteSortBackwards"),
            equalTo(false)
        )
    }
}
